// src/services/userService.js
// All Firestore read/write operations live here

import { db } from './firebase';
import {
  doc,
  getDoc,
  setDoc,
  updateDoc,
  collection,
  addDoc,
  getDocs,
  deleteDoc,
  query,
  where,
  serverTimestamp,
} from 'firebase/firestore';

// Save or update user profile
export async function saveProfile(uid, data) {
  const ref = doc(db, 'users', uid);
  await setDoc(ref, { ...data, updatedAt: serverTimestamp() }, { merge: true });
}

// Get user profile
export async function getProfile(uid) {
  const ref = doc(db, 'users', uid);
  const snap = await getDoc(ref);
  return snap.exists() ? snap.data() : null;
}

// Add a skill to user's skill list
export async function addSkill(uid, skill) {
  const ref = collection(db, 'users', uid, 'skills');
  const docRef = await addDoc(ref, { ...skill, createdAt: serverTimestamp() });
  return docRef.id;
}

// Get all skills for a user
export async function getSkills(uid) {
  const ref = collection(db, 'users', uid, 'skills');
  const snap = await getDocs(ref);
  return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}

// Update a skill
export async function updateSkill(uid, skillId, updates) {
  const ref = doc(db, 'users', uid, 'skills', skillId);
  await updateDoc(ref, updates);
}

// Delete a skill
export async function deleteSkill(uid, skillId) {
  const ref = doc(db, 'users', uid, 'skills', skillId);
  await deleteDoc(ref);
}

// Save a job description analysis result
export async function saveAnalysis(uid, analysis) {
  const ref = collection(db, 'users', uid, 'analyses');
  await addDoc(ref, { ...analysis, createdAt: serverTimestamp() });
}

// Get all analyses
export async function getAnalyses(uid) {
  const ref = collection(db, 'users', uid, 'analyses');
  const snap = await getDocs(ref);
  return snap.docs.map(d => ({ id: d.id, ...d.data() }));
}

// Log daily activity
export async function logActivity(uid, date) {
  const ref = doc(db, 'users', uid, 'activity', date);
  await setDoc(ref, { date, active: true }, { merge: true });
}

// Get activity for last N days
export async function getActivity(uid) {
  const ref = collection(db, 'users', uid, 'activity');
  const snap = await getDocs(ref);
  return snap.docs.map(d => d.data());
}
